#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    const long long L = 676767LL;
    const long long R = 450004500045000LL;
    while (T--) {
        long long X;
        scanf("%lld", &X);
        if (X >= L && X <= R) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

